import { tags } from 'decantr/tags';
import { createSignal, onMount, onDestroy } from 'decantr/state';
import { css } from 'decantr/css';
import { icon } from 'decantr/components';

code.example:
function TopStatusBar({ appName, version, mode, status, indicators = [] }) {
  const { div, span } = tags;
  const [time, setTime] = createSignal(new Date().toLocaleTimeString());

  onMount(() => {
    const interval = setInterval(() => setTime(new Date().toLocaleTimeString()), 1000);
    return () => clearInterval(interval);
  });

  const statusColors = {
    online: '#00FF00',
    offline: '#FF0000',
    busy: '#FFB000'
  };

  return div({ class: css('term-status _flex _aic _jcsb _px2 _h[24px] _bggreen _fgblack') },
    div({ class: css('_flex _aic _gap2') },
      span({ class: css('_fontbold') }, appName),
      span({ class: css('_fgmuted') }, `v${version}`),
      mode ? span({ class: css('_px1 _bg[rgba(0,0,0,0.2)] _r1') }, mode) : null
    ),
    div({ class: css('_flex _aic _gap4') },
      ...indicators.map(ind =>
        span({ class: css('_flex _aic _gap1'), style: `color: ${ind.color}` },
          icon(ind.icon, { size: '12' }), ind.label
        )
      ),
      span({ style: `color: ${statusColors[status]}` }, `[${status}]`),
      span({}, time)
    )
  );
}

