import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { icon } from 'decantr/components';

code.example:
function BottomStatusBar({ mode, file, line, col, encoding = 'UTF-8', branch }) {
  const { div, span } = tags;

  return div({ class: css('_flex _aic _jcsb _px2 _h[24px] _bgsurface _borderT _bordercolor[#333]') },
    div({ class: css('_flex _aic _gap2') },
      span({ class: css('_px1 _bgprimary _fgblack _fontbold') }, mode || 'NORMAL'),
      file ? span({ class: css('_fgmuted') }, file) : null,
      branch ? span({ class: css('_flex _aic _gap1 _fgmuted') }, icon('git-branch', { size: '12' }), branch) : null
    ),
    div({ class: css('_flex _aic _gap4') },
      span({ class: css('_fgmuted') }, encoding),
      span({}, `Ln ${line || 1}, Col ${col || 1}`)
    )
  );
}

function StatusBar({ position = 'bottom', ...props }) {
  return position === 'top'
    ? TopStatusBar(props)
    : BottomStatusBar(props);
}
